    import re
    present = 0
    total = 0
    prs = Presentation(modified_ppt_path)
    for idx, slide in enumerate(prs.slides):
        total += 1
        found = False
        for shape in slide.shapes:
            if not shape.has_text_frame:
                continue
            text = shape.text_frame.text.strip()
            # Accept 1 or '1', sometimes 'Slide 1'
            if re.fullmatch(r'(Slide )?%d' % (idx+1), text):
                found = True
                break
        if found:
            present += 1
    if total == 0:
        return ("No slides found in the presentation.", 0.0)
