        return ("All slides have their slide number present.", 1.0)
    else:
        return (f"{present} out of {total} slides have a visible slide number.", score)

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    import re
    prs = Presentation(modified_ppt_path)
    total = 0
    correct_pos = 0

    for idx, slide in enumerate(prs.slides):
        slide_num_ok = False
        for shape in slide.shapes:
            if not shape.has_text_frame:
                continue
            text = shape.text_frame.text.strip()

            # Check if this looks like a slide number for this slide
            expected_numbers = [str(idx+1), f"Slide {idx+1}"]
            if text in expected_numbers or re.fullmatch(r'(Slide )?%d' % (idx+1), text):
                # Assess shape position - use more reasonable thresholds
                SLIDE_W = prs.slide_width
                SLIDE_H = prs.slide_height

                # Calculate position percentages
                right_pct = ((shape.left + shape.width) / SLIDE_W) * 100
                bottom_pct = ((shape.top + shape.height) / SLIDE_H) * 100

                # Accept if shape is in bottom-right area (flexible thresholds)
                # Right side: at least 70% from left edge
                # Bottom: at least 85% from top edge  
                if right_pct >= 70 and bottom_pct >= 85:
                    slide_num_ok = True
                    break

        total += 1
        if slide_num_ok:
            correct_pos += 1

    if total == 0:
        return ("No slides in presentation.", 0.0)

    score = correct_pos / total
    if score == 1.0:
        return ("All slide numbers are positioned in the bottom right area.", 1.0)
    else:
        return (f"{correct_pos} of {total} slides have the slide number at the correct position.", score)

def compute_score() -> tuple[str, float]:
    # For slide numbering task, allow text boxes and slide number placeholders
    # Only reject major content changes, slide additions/removals
    unexpected = False
    messages = []

    # 1. Any added/removed slides?
    if ppt_diff.added_slides or ppt_diff.removed_slides:
        unexpected = True
        messages.append("Slides were added or removed.")

    # 2. Check for major content changes (ignore minor animation/transition changes 
    # that happen naturally when adding slide numbers)
    from pptx import Presentation
    import re
    original = Presentation(original_ppt_path)
    modified = Presentation(modified_ppt_path)

    if len(original.slides) != len(modified.slides):
        unexpected = True
        messages.append("Number of slides changed.")

    # Precompile slide number text regex
    import re
    slide_number_re = re.compile(r'^(slide\s+)?(\d+|\*)$')

    # Check for shapes that aren't slide numbers and ensure existing content not modified
    for i, (mslide, oslide) in enumerate(zip(modified.slides, original.slides)):
        added_shapes = []

        # Build lookup of original shapes by name -> text (normalized)
        original_shape_text = {}
        for oshape in oslide.shapes:
            oname = getattr(oshape, "name", "")
            if oname and hasattr(oshape, "has_text_frame") and oshape.has_text_frame and oshape.text_frame.text:
                original_shape_text[oname] = re.sub(r"\s+", " ", oshape.text_frame.text.strip()).lower()

        # Track if existing shape text changed
        # Find shapes that are new in modified slide & detect modifications
        for shape in mslide.shapes:
            shape_name = getattr(shape, "name", "")
            shape_type = getattr(shape, "shape_type", None)

            # Skip if it's a slide number placeholder or similar
            if ("slide number" in shape_name.lower() or 
                "placeholder" in shape_name.lower()):
                continue

            # Check if this shape has text that looks like a slide number
            if (hasattr(shape, "has_text_frame") and shape.has_text_frame and shape.text_frame.text):
                text = shape.text_frame.text.strip()
                # Match various slide number formats
                if slide_number_re.match(text.lower()) or text.isdigit():
                    continue

            # Check if this shape exists in original (by name/content)
            found_in_original = False
            for oshape in oslide.shapes:
                if (getattr(oshape, "name", "") == shape_name and shape_name):
                    found_in_original = True
                    break

            if not found_in_original:
                added_shapes.append(shape)
            else:
                # Potential modification: compare text content if both have text frames
                if (shape_name in original_shape_text and hasattr(shape, "has_text_frame") and shape.has_text_frame):
                    m_text_raw = shape.text_frame.text or ""
                    m_text_norm = re.sub(r"\s+", " ", m_text_raw.strip()).lower()
                    o_text_norm = original_shape_text.get(shape_name, "")
                    if m_text_norm != o_text_norm:
                        # Allow if original empty and modified only added a slide number text
                        if not (o_text_norm == "" and slide_number_re.match(m_text_norm)):
                            unexpected = True
                            messages.append(f"Content of shape '{shape_name}' modified on slide {i+1}.")

        # Only flag non-slide-number additions as unexpected
        significant_additions = []
        for shape in added_shapes:
            shape_name = getattr(shape, "name", "")
            if not ("slide number" in shape_name.lower() or "placeholder" in shape_name.lower()):
                # Check if the shape contains slide number text
                if hasattr(shape, "has_text_frame") and shape.has_text_frame:
                    text = shape.text_frame.text.strip()
                    if not slide_number_re.match(text.lower()) and not text.isdigit():
                        significant_additions.append(shape)
                else:
                    significant_additions.append(shape)

        if significant_additions:
            for shape in significant_additions:
                unexpected = True
                shape_name = getattr(shape, "name", "unnamed")
                messages.append(f"Unexpected non-slide-number shape '{shape_name}' added on slide {i+1}.")

    if unexpected:
        return ("; ".join(messages), 0.0)
    return ("No significant extraneous modifications detected (slide number additions are expected).", 1.0)
